116:     GrpcMuxWatchImpl(const absl::flat_hash_set<std::string>& resources,
117:                      SubscriptionCallbacks& callbacks,
118:                      OpaqueResourceDecoderSharedPtr resource_decoder, const std::string& type_url,
119:                      GrpcMuxImpl& parent, const SubscriptionOptions& options,
120:                      const LocalInfo::LocalInfo& local_info,
121:                      EdsResourcesCacheOptRef eds_resources_cache)
122:         : callbacks_(callbacks), resource_decoder_(resource_decoder), type_url_(type_url),
123:           parent_(parent), subscription_options_(options), local_info_(local_info),
124:           watches_(parent.apiStateFor(type_url).watches_),
125:           eds_resources_cache_(eds_resources_cache) {
126:       updateResources(resources);
127:       // If eds resources cache is provided, then the type must be ClusterLoadAssignment.
128:       ASSERT(
129:           !eds_resources_cache_.has_value() ||
130:           (type_url == Config::getTypeUrl<envoy::config::endpoint::v3::ClusterLoadAssignment>()));
131:     }
132: 
133:     ~GrpcMuxWatchImpl() override {
134:       watches_.erase(iter_);
135:       if (!resources_.empty()) {
136:         parent_.queueDiscoveryRequest(type_url_);
137:         if (eds_resources_cache_.has_value()) {
138:           removeResourcesFromCache(resources_);
139:         }
140:       }
141:     }
142: 
143:     void update(const absl::flat_hash_set<std::string>& resources) override {
144:       watches_.erase(iter_);
145:       if (!resources_.empty()) {
146:         parent_.queueDiscoveryRequest(type_url_);
147:       }
148:       updateResources(resources);
149:       parent_.queueDiscoveryRequest(type_url_);
150:     }
151: 
152:     // Maintain deterministic wire ordering via ordered std::set.
153:     std::set<std::string> resources_;
154:     SubscriptionCallbacks& callbacks_;
155:     OpaqueResourceDecoderSharedPtr resource_decoder_;
156:     const std::string type_url_;
157:     GrpcMuxImpl& parent_;
158: 
159:   private:
160:     void updateResources(const absl::flat_hash_set<std::string>& resources) {
161:       // Finding the list of removed resources by keeping the current resources
162:       // set until the end the function and computing the diff.
163:       // Temporarily keep the resources prior to the update to find which ones
164:       // were removed.
165:       std::set<std::string> previous_resources;
166:       previous_resources.swap(resources_);
167:       std::transform(
168:           resources.begin(), resources.end(), std::inserter(resources_, resources_.begin()),
169:           [this](const std::string& resource_name) -> std::string {
170:             if (XdsResourceIdentifier::hasXdsTpScheme(resource_name)) {
171:               auto xdstp_resource_or_error = XdsResourceIdentifier::decodeUrn(resource_name);
172:               THROW_IF_STATUS_NOT_OK(xdstp_resource_or_error, throw);
173:               auto xdstp_resource = xdstp_resource_or_error.value();
174:               if (subscription_options_.add_xdstp_node_context_params_) {
175:                 const auto context = XdsContextParams::encodeResource(
176:                     local_info_.contextProvider().nodeContext(), xdstp_resource.context(), {}, {});
177:                 xdstp_resource.mutable_context()->CopyFrom(context);
178:               }
179:               XdsResourceIdentifier::EncodeOptions encode_options;
180:               encode_options.sort_context_params_ = true;
181:               return XdsResourceIdentifier::encodeUrn(xdstp_resource, encode_options);
182:             }
183:             return resource_name;
184:           });
185:       if (eds_resources_cache_.has_value()) {
186:         // Compute the removed resources and remove them from the cache.
187:         std::set<std::string> removed_resources;
188:         std::set_difference(previous_resources.begin(), previous_resources.end(),
189:                             resources_.begin(), resources_.end(),
190:                             std::inserter(removed_resources, removed_resources.begin()));
191:         removeResourcesFromCache(removed_resources);
192:       }
193:       // move this watch to the beginning of the list
194:       iter_ = watches_.emplace(watches_.begin(), this);
195:     }
196: 
197:     void removeResourcesFromCache(const std::set<std::string>& resources_to_remove) {
198:       ASSERT(eds_resources_cache_.has_value());
199:       // Iterate over the resources to remove, and if no other watcher
200:       // registered for that resource, remove it from the cache.
201:       for (const auto& resource_name : resources_to_remove) {
202:         // Counts the number of watchers that watch the resource.
203:         uint32_t resource_watchers_count = 0;
204:         for (const auto& watch : watches_) {
205:           // Skip the current watcher as it is intending to remove the resource.
206:           if (watch == this) {
207:             continue;
208:           }
209:           if (watch->resources_.find(resource_name) != watch->resources_.end()) {
210:             resource_watchers_count++;
211:           }
212:         }
213:         // Other than "this" watcher, the resource is not watched by any other
214:         // watcher, so it can be removed.
215:         if (resource_watchers_count == 0) {
216:           eds_resources_cache_->removeResource(resource_name);
217:         }
218:       }
219:     }
220: 
221:     using WatchList = std::list<GrpcMuxWatchImpl*>;
222:     const SubscriptionOptions& subscription_options_;
223:     const LocalInfo::LocalInfo& local_info_;
224:     WatchList& watches_;
225:     WatchList::iterator iter_;
226:     // Optional cache for the specific ClusterLoadAssignments of this watch.
227:     EdsResourcesCacheOptRef eds_resources_cache_;
228:   };
