51:   void establishNewStream() override {
52:     stream_intentionally_closed_ = false;
53:     ENVOY_LOG(debug, "Establishing new gRPC bidi stream to {} for {}", async_client_.destination(),
54:               service_method_.DebugString());
55:     if (stream_ != nullptr) {
56:       ENVOY_LOG(warn, "gRPC bidi stream to {} for {} already exists!", async_client_.destination(),
57:                 service_method_.DebugString());
58:       return;
59:     }
60:     stream_ = async_client_->start(service_method_, *this, Http::AsyncClient::StreamOptions());
61:     if (stream_ == nullptr) {
62:       ENVOY_LOG(debug, "Unable to establish new stream to configuration server {}",
63:                 async_client_.destination());
64:       callbacks_->onEstablishmentFailure();
65:       setRetryTimer();
66:       return;
67:     }
68:     control_plane_stats_.connected_state_.set(1);
69:     callbacks_->onStreamEstablished();
70:   }
71: 
72:   bool grpcStreamAvailable() const override { return stream_ != nullptr; }
73: 
74:   void sendMessage(const RequestProto& request) override { stream_->sendMessage(request, false); }
75: 
76:   // Grpc::AsyncStreamCallbacks
77:   void onCreateInitialMetadata(Http::RequestHeaderMap& metadata) override {
78:     UNREFERENCED_PARAMETER(metadata);
79:   }
80: 
81:   void onReceiveInitialMetadata(Http::ResponseHeaderMapPtr&& metadata) override {
82:     UNREFERENCED_PARAMETER(metadata);
83:   }
84: 
85:   void onReceiveMessage(ResponseProtoPtr<ResponseProto>&& message) override {
86:     // Reset here so that it starts with fresh backoff interval on next disconnect.
87:     backoff_strategy_->reset();
88:     // Clear here instead of on stream establishment in case streams are immediately closed
89:     // repeatedly.
90:     clearCloseStatus();
91:     // Sometimes during hot restarts this stat's value becomes inconsistent and will continue to
92:     // have 0 until it is reconnected. Setting here ensures that it is consistent with the state of
93:     // management server connection.
94:     control_plane_stats_.connected_state_.set(1);
95:     callbacks_->onDiscoveryResponse(std::move(message), control_plane_stats_);
96:   }
97: 
98:   void onReceiveTrailingMetadata(Http::ResponseTrailerMapPtr&& metadata) override {
99:     UNREFERENCED_PARAMETER(metadata);
100:   }
101: 
102:   void onRemoteClose(Grpc::Status::GrpcStatus status, const std::string& message) override {
103:     logClose(status, message);
104:     stream_ = nullptr;
105:     control_plane_stats_.connected_state_.set(0);
106:     callbacks_->onEstablishmentFailure();
107:     // Only retry the timer if not intentionally closed by Envoy.
108:     if (!stream_intentionally_closed_) {
109:       setRetryTimer();
110:     }
111:   }
112: 
113:   void maybeUpdateQueueSizeStat(uint64_t size) override {
114:     // Although request_queue_.push() happens elsewhere, the only time the queue is non-transiently
115:     // non-empty is when it remains non-empty after a drain attempt. (The push() doesn't matter
116:     // because we always attempt this drain immediately after the push). Basically, a change in
117:     // queue length is not "meaningful" until it has persisted until here. We need the
118:     // if(>0 || used) to keep this stat from being wrongly marked interesting by a pointless set(0)
119:     // and needlessly taking up space. The first time we set(123), used becomes true, and so we will
120:     // subsequently always do the set (including set(0)).
121:     if (size > 0 || control_plane_stats_.pending_requests_.used()) {
122:       control_plane_stats_.pending_requests_.set(size);
123:     }
124:   }
125: 
126:   bool checkRateLimitAllowsDrain() override {
127:     if (!rate_limiting_enabled_ || limit_request_->consume(1, false)) {
128:       return true;
129:     }
130:     ASSERT(drain_request_timer_ != nullptr);
131:     control_plane_stats_.rate_limit_enforced_.inc();
132:     // Enable the drain request timer.
133:     if (!drain_request_timer_->enabled()) {
134:       drain_request_timer_->enableTimer(limit_request_->nextTokenAvailable());
135:     }
136:     return false;
137:   }
138: 
139:   void closeStream() override {
140:     ENVOY_LOG_MISC(debug, "Intentionally closing the gRPC stream to {}",
141:                    async_client_.destination());
142:     retry_timer_->disableTimer();
143:     if (rate_limiting_enabled_) {
144:       drain_request_timer_->disableTimer();
145:     }
146:     control_plane_stats_.connected_state_.set(0);
147:     logClose(Grpc::Status::WellKnownGrpcStatus::Ok, "Envoy initiated close.");
148:     if (stream_ != nullptr) {
149:       stream_.resetStream();
150:       stream_ = nullptr;
151:     }
152:     stream_intentionally_closed_ = true;
153:   }
154: 
155:   absl::optional<Grpc::Status::GrpcStatus> getCloseStatusForTest() const {
156:     return last_close_status_;
157:   }
158: 
159: private:
160:   void setRetryTimer() {
161:     retry_timer_->enableTimer(std::chrono::milliseconds(backoff_strategy_->nextBackOffMs()));
162:   }
163: 
164:   // Log level should be reduced when the remote close failure is `Ok` or is retriable and has only
165:   // been occurring for a short amount of time.
166:   void logClose(Grpc::Status::GrpcStatus status, const std::string& message) {
167:     if (Grpc::Status::WellKnownGrpcStatus::Ok == status) {
168:       ENVOY_LOG(debug, "{} gRPC config stream to {} closed: {}, {}", service_method_.name(),
169:                 async_client_.destination(), status, message);
170:       return;
171:     }
172: 
173:     if (!isNonRetriableFailure(status)) {
174:       // When the failure is considered non-retriable, warn.
175:       ENVOY_LOG(warn, "{} gRPC config stream to {} closed: {}, {}", service_method_.name(),
176:                 async_client_.destination(), status, message);
177:       return;
178:     }
179: 
180:     if (!isCloseStatusSet()) {
181:       // For the first failure, record its occurrence and log at the debug level.
182:       ENVOY_LOG(debug, "{} gRPC config stream to {} closed: {}, {}", service_method_.name(),
183:                 async_client_.destination(), status, message);
184:       setCloseStatus(status, message);
185:       return;
186:     }
187: 
188:     const auto duration_since_first_close = time_source_.monotonicTime() - last_close_time_;
189:     const uint64_t seconds_since_first_close =
190:         std::chrono::duration_cast<std::chrono::seconds>(duration_since_first_close).count();
191:     const Grpc::Status::GrpcStatus close_status = last_close_status_.value();
192: 
193:     if (status != close_status) {
194:       // This is a different failure. Warn on both statuses and remember the new one.
195:       ENVOY_LOG(warn,
196:                 "{} gRPC config stream to {} closed: {}, {} (previously {}, {} since {}s ago)",
197:                 service_method_.name(), async_client_.destination(), status, message, close_status,
198:                 last_close_message_, seconds_since_first_close);
199:       setCloseStatus(status, message);
200:       return;
201:     }
202: 
203:     // #18508: The error message may have changed.
204:     // To reduce noise, do not update the last close time, or use the message to distinguish the
205:     // error in the previous condition.
206:     last_close_message_ = message;
207: 
208:     const uint64_t ms_since_first_close =
209:         std::chrono::duration_cast<std::chrono::milliseconds>(duration_since_first_close).count();
210:     if (backoff_strategy_->isOverTimeLimit(ms_since_first_close)) {
211:       // Warn if we are over the time limit.
212:       ENVOY_LOG(warn, "{} gRPC config stream to {} closed since {}s ago: {}, {}",
213:                 service_method_.name(), async_client_.destination(), seconds_since_first_close,
214:                 close_status, message);
215:       return;
216:     }
217: 
218:     // Failure is retriable and new enough to only log at the debug level.
219:     ENVOY_LOG(debug, "{} gRPC config stream to {} closed: {}, {}", service_method_.name(),
220:               async_client_.destination(), status, message);
221:   }
222: 
223:   bool isNonRetriableFailure(Grpc::Status::GrpcStatus status) {
224:     // Status codes from https://grpc.github.io/grpc/core/md_doc_statuscodes.html that potentially
225:     // indicate a high likelihood of success after retrying with backoff.
226:     //
227:     // - DeadlineExceeded may be from a latency spike
228:     // - ResourceExhausted may be from a rate limit with a short window or a transient period of too
229:     //   many connections
230:     // - Unavailable is meant to be used for a transient downtime
231:     return Grpc::Status::WellKnownGrpcStatus::DeadlineExceeded == status ||
232:            Grpc::Status::WellKnownGrpcStatus::ResourceExhausted == status ||
233:            Grpc::Status::WellKnownGrpcStatus::Unavailable == status;
234:   }
235: 
236:   void clearCloseStatus() { last_close_status_ = absl::nullopt; }
237:   bool isCloseStatusSet() { return last_close_status_.has_value(); }
238: 
239:   void setCloseStatus(Grpc::Status::GrpcStatus status, const std::string& message) {
240:     last_close_status_ = status;
241:     last_close_time_ = time_source_.monotonicTime();
242:     last_close_message_ = message;
243:   }
244: 
245:   GrpcStreamCallbacks<ResponseProto>* const callbacks_;
246: 
247:   Grpc::AsyncClient<RequestProto, ResponseProto> async_client_;
248:   Grpc::AsyncStream<RequestProto> stream_{};
249:   const Protobuf::MethodDescriptor& service_method_;
250:   ControlPlaneStats control_plane_stats_;
251: 
252:   // Reestablishes the gRPC channel when necessary, with some backoff politeness.
253:   Event::TimerPtr retry_timer_;
254:   TimeSource& time_source_;
255:   BackOffStrategyPtr backoff_strategy_;
256: 
257:   // Prevents the Envoy from making too many requests.
258:   TokenBucketPtr limit_request_;
259:   const bool rate_limiting_enabled_;
260:   Event::TimerPtr drain_request_timer_;
261: 
262:   // Records the initial message and timestamp of the most recent remote closes with the same
263:   // status.
264:   absl::optional<Grpc::Status::GrpcStatus> last_close_status_;
265:   std::string last_close_message_;
266:   MonotonicTime last_close_time_;
267: 
268:   bool stream_intentionally_closed_{false};
269: };
